    /// <summary>
    /// Get a localized string for the given key in the currently active language.
    /// Falls back to en-US if the language is unknown, then to the key itself if the key is unknown.
    /// </summary>
    public static string GetString(string key)
    {
        var lang = LocalizationService.ActiveLanguage;
        if (All.TryGetValue(lang, out var dict) && dict.TryGetValue(key, out var value))
            return value;
        if (All.TryGetValue(DefaultLanguage, out var fallback) && fallback.TryGetValue(key, out var fallbackValue))
            return fallbackValue;
        return key;
    }
